// Check VoipLine balance + channel usage via the proxy. Balance endpoint also reflects channel usage.
// NOTE: the concurrent-usage field name is mapped defensively and must be confirmed at live integration.
const helpers = this.helpers;
const PROXY = 'https://workers.prisoncall.com.au/voipline-proxy';
let resp = {};
try {
  resp = await helpers.httpRequest({ method: 'POST', url: PROXY, headers: { 'X-Proxy-Secret': $env.VOIPLINE_PROXY_SECRET, 'X-VoipLine-Path': '/api/customer/core/balance', 'X-VoipLine-Method': 'GET', 'Content-Type': 'application/json' }, json: true });
} catch (e) { resp = { error: String(e.message || e) }; }

const channels = 4; // 8SC PRO = 4 simultaneous calls
let concurrent = (resp && (resp.concurrent_calls != null ? resp.concurrent_calls : resp.channels_in_use != null ? resp.channels_in_use : resp.active_channels != null ? resp.active_channels : (resp.usage && resp.usage.concurrent))) || 0;
concurrent = Number(concurrent) || 0;
const pct = Math.round((concurrent / channels) * 100);

// >75% of 4 = 3+ concurrent -> scale-up advisory. <50% = <2 -> scale-down possible.
// NOTE: at live integration, store the last advisory in a data table and only send on CHANGE to avoid hourly repeats.
let advisory = 'none';
let notify = false;
let text = '';
if (concurrent >= 3) {
  advisory = 'scale_up';
  notify = true;
  text = 'Prisoncall SIP advisory: ' + concurrent + '/' + channels + ' channels in use (' + pct + '%). Approaching capacity - consider upgrading the 3CX SC tier / SIP channels. No auto-purchase - owner decision only.';
} else if (concurrent < 2) {
  advisory = 'scale_down_possible';
  notify = true;
  text = 'Prisoncall SIP advisory: usage at ' + concurrent + '/' + channels + ' channels (' + pct + '%), below 50%. Scale-down is possible if sustained. Owner decision only.';
}

return [{ json: { balance: resp, concurrent: concurrent, channels: channels, pct: pct, advisory: advisory, notify: notify, advisory_text: text } }];

// Send the capacity advisory SMS to the owner. NEVER auto-purchases channels.
const helpers = this.helpers;
const d = $json;
const auth = 'Basic ' + Buffer.from($env.CLICKSEND_USERNAME + ':' + $env.CLICKSEND_API_KEY).toString('base64');
const resp = await helpers.httpRequest({ method: 'POST', url: 'https://rest.clicksend.com/v3/sms/send', headers: { Authorization: auth, 'Content-Type': 'application/json' }, body: { messages: [{ source: 'n8n', from: $env.CLICKSEND_DEDICATED_NUMBER, to: $env.OWNER_MOBILE, body: d.advisory_text }] }, json: true });
return [{ json: { ...d, owner_sms: resp } }];
